  "sources": ["src/app/features/coach/messages/messages.component.css"],
  "sourcesContent": [".page { display:flex;flex-direction:column;gap:24px;height:calc(100vh - var(--topbar-h) - 56px); }\r\n.page-header { flex-shrink:0; }\r\n.chat-layout { display:grid;grid-template-columns:300px 1fr;gap:16px;flex:1;overflow:hidden;min-height:0; }\r\n@media(max-width:768px) { .chat-layout { grid-template-columns:1fr; } }\r\n.conv-panel { display:flex;flex-direction:column;overflow:hidden; }\r\n.conv-search { display:flex;align-items:center;gap:8px;padding:12px 16px;border-bottom:1px solid var(--border); }\r\n.conv-search input { border:none;outline:none;font-size:13px;flex:1;font-family:inherit;color:var(--text-primary); }\r\n.conv-search input::placeholder { color:var(--text-muted); }\r\n.conv-list { flex:1;overflow-y:auto; }\r\n.conv-item { display:flex;align-items:center;gap:11px;padding:13px 16px;cursor:pointer;transition:background 0.15s;position:relative; }\r\n.conv-item.active { background:var(--orange-light); }\r\n.conv-item:hover:not(.active) { background:rgba(0,0,0,0.03); }\r\n.conv-avatar { width:40px;height:40px;border-radius:11px;color:white;display:flex;align-items:center;justify-content:center;font-size:13px;font-weight:700;flex-shrink:0; }\r\n.conv-info { flex:1;min-width:0; }\r\n.conv-top { display:flex;justify-content:space-between;align-items:baseline;margin-bottom:3px; }\r\n.conv-name { font-size:13px;font-weight:700;color:var(--text-primary); }\r\n.conv-time { font-size:10px;color:var(--text-muted); }\r\n.conv-preview { font-size:12px;color:var(--text-secondary);white-space:nowrap;overflow:hidden;text-overflow:ellipsis; }\r\n.unread-badge { background:var(--orange);color:white;border-radius:50%;width:18px;height:18px;font-size:10px;font-weight:700;display:flex;align-items:center;justify-content:center;flex-shrink:0; }\r\n.chat-area { display:flex;flex-direction:column;overflow:hidden; }\r\n.chat-header { display:flex;align-items:center;gap:12px;padding:14px 18px;border-bottom:1px solid var(--border);flex-shrink:0; }\r\n.online-status { font-size:11px;color:var(--text-muted);display:flex;align-items:center;gap:5px;margin-top:2px; }\r\n.messages-body { flex:1;overflow-y:auto;padding:18px;display:flex;flex-direction:column;gap:10px; }\r\n.msg-wrap { display:flex; }\r\n.msg-wrap.mine { justify-content:flex-end; }\r\n.msg-bubble { max-width:65%;padding:10px 14px;border-radius:16px;background:white;border:1px solid var(--border);position:relative; }\r\n.msg-bubble.mine { background:linear-gradient(135deg,var(--orange),#FF7A40);color:white;border:none; }\r\n.msg-bubble p { font-size:13px;line-height:1.5; }\r\n.msg-time { font-size:10px;opacity:0.55;display:block;margin-top:4px;text-align:right; }\r\n.chat-input { display:flex;align-items:center;gap:10px;padding:14px 18px;border-top:1px solid var(--border);flex-shrink:0; }\r\n.chat-input input { flex:1;border:1px solid var(--border);border-radius:10px;padding:10px 14px;font-size:13px;outline:none;font-family:inherit;background:var(--bg-app); }\r\n.chat-input input:focus { border-color:var(--orange); }\r\n.input-icon-btn { background:none;border:none;cursor:pointer;color:var(--text-muted);padding:8px;border-radius:8px;transition:all 0.15s;display:flex; }\r\n.input-icon-btn:hover { background:var(--orange-light);color:var(--orange); }\r\n.send-btn { background:linear-gradient(135deg,var(--orange),#FF7A40);border:none;cursor:pointer;color:white;padding:10px 14px;border-radius:10px;display:flex;align-items:center;justify-content:center;transition:all 0.15s; }\r\n.send-btn:hover { transform:translateY(-1px);box-shadow:0 4px 12px rgba(232,98,42,0.4); }\r\n.empty-chat { display:flex;flex-direction:column;align-items:center;justify-content:center;height:100%;color:var(--text-muted);gap:12px; }\r\n.empty-chat svg { opacity:0.25; }\r\n"],
